// Old buggy strategy — uniform totalShift applied to every market's YES.
const closes = ctx.underlying.klines.map((k) => k.close);
const rsi = ctx.helpers.rsi(closes, 14);
const emaFast = ctx.helpers.emaArray(closes, 12).at(-1);
const emaSlow = ctx.helpers.emaArray(closes, 26).at(-1);
const emaTrend = Math.sign(emaFast - emaSlow);
const recentCloses = closes.slice(-4);
const shortMomentum =
  recentCloses.length >= 2
    ? (recentCloses.at(-1) - recentCloses[0]) / recentCloses[0]
    : 0;

const rsiShift = (rsi - 50) / 50 * 0.5;
const emaShift = emaTrend * 0.3;
const shortShift = shortMomentum * 10;
const totalShift = rsiShift + emaShift + shortShift;

const logit = (p) => Math.log(p / (1 - p));
const sigmoid = (x) => 1 / (1 + Math.exp(-x));
const clamp = (p) => Math.min(Math.max(p, 1e-6), 1 - 1e-6);

const yesProbFor = (mCtx) => {
  switch (mCtx.market.questionType) {
    case "above": return ctx.helpers.bsAbove(mCtx);
    case "below": return 1 - ctx.helpers.bsAbove(mCtx);
    case "range": return ctx.helpers.bsRange(mCtx);
    case "hit":   return ctx.helpers.bsOneTouch(mCtx);
    default: return null;
  }
};

const THRESHOLD = 0.04;

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, questionType: market.questionType, decision: "hold", reason: "closed" };
    }
    if (market.questionType === "unknown" || market.strike === null) {
      return { question: market.question, questionType: market.questionType, decision: "hold", reason: "no strike" };
    }
    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };
    let probs;
    if (market.questionType === "firstHit") {
      probs = ctx.helpers.firstHitProbabilities(mCtx, { seed: 42 });
    } else {
      const yes0 = yesProbFor(mCtx);
      if (yes0 === null) return { question: market.question, questionType: market.questionType, decision: "hold", reason: "unsupported" };
      const yes = sigmoid(logit(clamp(yes0)) + totalShift);
      probs = ctx.helpers.binaryProbsFromYesProb(mCtx, yes);
    }
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    const reason = `totalShift=${totalShift.toFixed(3)} edge=${best.edge.toFixed(3)}`;
    const base = {
      question: market.question,
      questionType: market.questionType,
      probs,
      spot: ctx.underlying.price,
      strike: market.strike,
      strike2: market.strike2 ?? null,
    };
    if (best.edge < THRESHOLD) {
      return { ...base, decision: "hold", edge: best.edge, reason };
    }
    return { ...base, decision: "buy", side: best.label, fairPrice: best.fairPrice, marketPrice: best.marketPrice, edge: best.edge, reason };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
